DROP TABLE IF EXISTS `oner_hayvan_varliklari`;

CREATE TABLE `oner_hayvan_varliklari` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `tarih` DATETIME,
  `sigir_varligi_bas` BIGINT,
  `manda_varligi_bas` BIGINT,
  `toplam_buyukbas_varligi_bas` BIGINT,
  `koyun_varligi_bas` BIGINT,
  `keci_varligi_bas` BIGINT,
  `toplam_kucukbas_varligi_bas` BIGINT,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

